// Verify the DIRECTION_BATCH_SIZE config is set and used by analyzeDirections.
// This is a unit-level check — it validates the config exists with a sensible value,
// ensuring the staggered batching mechanism is properly configured.
async function testDirectionsBatchConfig() {
  // Config should exist and be a positive number
  const batchSize = config.get('DIRECTION_BATCH_SIZE');
  assert(batchSize !== null && batchSize !== undefined, 'DIRECTION_BATCH_SIZE config should be defined');
  assert(typeof batchSize === 'number', 'DIRECTION_BATCH_SIZE should be a number, got: ' + typeof batchSize);
  assert(batchSize > 0, 'DIRECTION_BATCH_SIZE should be positive, got: ' + batchSize);
  assert(batchSize <= 8, 'DIRECTION_BATCH_SIZE should be <= 8 (total directions), got: ' + batchSize);

  // Default should be 2 — optimal for avoiding rate limits while keeping latency low
  assertEquals(batchSize, 2, 'Default DIRECTION_BATCH_SIZE should be 2');
}
